#!/usr/bin/env python
import json
import re
import os

with open("/tmp/page_refs2.txt", "r") as f:
    lines = f.read().splitlines()

# Remove last "TOTAL" line if present
if lines and lines[-1].startswith("TOTAL:"):
    lines = lines[:-1]

results = []

def is_test_file(rel):
    parts = rel.split("/")
    # Check if any directory is named tests or testapp tests
    if "tests" in parts:
        return True
    filename = parts[-1]
    if filename == "tests.py" or filename.startswith("test_") or filename.endswith("_test.py"):
        return True
    return False

for line in lines:
    m = re.match(r"^(/[^:]+/wagtail/([^:]+\.py)):(\d+): (.*)$", line)
    if not m:
        continue
    path, rel, lineno, content = m.group(1), m.group(2), int(m.group(3)), m.group(4)

    if is_test_file(rel):
        continue

    stripped = content.strip()

    # Exclude re-exports
    if rel.endswith("__init__.py"):
        continue

    # Exclude comments
    if stripped.startswith("#"):
        continue

    # Exclude lines that are pure string literals (translation strings mentioning Page)
    if re.match(r'^(?:_\()?["\'][^"\']*\bPage\b[^"\']*["\']', stripped):
        continue

    # Exclude docstring lines with >>> examples
    if ">>>" in stripped:
        continue

    # Exclude query.py docstring lines 436-474 (examples)
    if rel == "wagtail/query.py" and 436 <= lineno <= 474:
        continue

    # Exclude coreutils docstring line 397
    if rel == "wagtail/coreutils.py" and lineno == 397:
        continue

    # Exclude url_routing docstring lines 3,6
    if rel == "wagtail/url_routing.py" and lineno in (3, 6):
        continue

    # Exclude title_field_panel docstring lines 11,18
    if rel == "wagtail/admin/panels/title_field_panel.py" and lineno in (11, 18):
        continue

    # Exclude tables/pages.py docstring line 72
    if rel == "wagtail/admin/ui/tables/pages.py" and lineno == 72:
        continue

    # Exclude settings/models.py docstring line 78
    if rel == "wagtail/contrib/settings/models.py" and lineno == 78:
        continue

    # Exclude userbar docstring line 11
    if rel == "wagtail/admin/templatetags/wagtailuserbar.py" and lineno == 11:
        continue

    # Exclude action docstrings (line 11, 42, 78)
    if rel == "wagtail/actions/copy_for_translation.py" and lineno == 11:
        continue
    if rel == "wagtail/actions/create_alias.py" and lineno == 42:
        continue
    if rel == "wagtail/actions/copy_page.py" and lineno == 78:
        continue

    # Exclude rich_text/__init__.py docstring line 124
    if rel == "wagtail/rich_text/__init__.py" and lineno == 124:
        continue

    # Exclude forms/models.py comment line 71
    if rel == "wagtail/admin/forms/models.py" and lineno == 71:
        continue

    # Exclude checks.py docstring lines
    if rel == "wagtail/checks.py" and lineno in (20, 23, 24):
        continue

    # Exclude models/i18n.py docstring line 375
    if rel == "wagtail/models/i18n.py" and lineno == 375:
        continue

    # Exclude reference_index.py docstring line 228
    if rel == "wagtail/models/reference_index.py" and lineno == 228:
        continue

    # Exclude locks.py docstring line 15
    if rel == "wagtail/locks.py" and lineno == 15:
        continue

    # Exclude wagtail_hooks.py docstring line 593
    if rel == "wagtail/wagtail_hooks.py" and lineno == 593:
        continue

    # Exclude contrib/forms/models.py docstring line 146
    if rel == "wagtail/contrib/forms/models.py" and lineno == 146:
        continue

    # Exclude contrib/redirects/models.py docstring lines 126
    if rel == "wagtail/contrib/redirects/models.py" and lineno == 126:
        continue

    # Exclude contrib/frontend_cache/utils.py docstring lines 126, 155
    if rel == "wagtail/contrib/frontend_cache/utils.py" and lineno in (126, 155):
        continue

    # Exclude contrib/routable_page/models.py docstring lines 51, 177, 178, 179
    if rel == "wagtail/contrib/routable_page/models.py" and lineno in (51, 177, 178, 179):
        continue

    # Exclude models/pages.py docstring/comment lines that are not code
    if rel == "wagtail/models/pages.py" and lineno in (
        116, 123, 127, 1329, 1540, 1564, 1626, 1860, 2128, 2129, 259, 262, 421, 430, 433, 859, 955, 988
    ):
        continue

    # Exclude workflow docstring lines
    if rel == "wagtail/models/workflows.py" and lineno in (1226, 1231):
        continue

    # Exclude signal_handlers docstring? line 39 is code (log message)

    # Exclude admin/templatetags/wagtailadmin_tags.py docstring lines 174, 175, 176, 428
    if rel == "wagtail/admin/templatetags/wagtailadmin_tags.py" and lineno in (174, 175, 176, 428, 203):
        continue

    # Exclude styleguide/views.py docstring lines 37
    if rel == "wagtail/contrib/styleguide/views.py" and lineno == 37:
        continue

    # Exclude publishing_panel docstring line 57? No, it's code (isinstance check)
    # Actually publishing_panel line 57 is code: if isinstance(self.instance, Page): - keep it

    # Exclude admin/checks.py docstring line 151, 157? They are not in the list.

    # Exclude viewsets/pages.py docstring lines 283, 534, 536
    if rel == "wagtail/admin/viewsets/pages.py" and lineno in (283, 534, 536, 684):
        continue

    # Exclude api/v2/serializers.py docstring lines 133, 160, 181
    if rel == "wagtail/api/v2/serializers.py" and lineno in (133, 160, 181):
        continue

    # Exclude contrib/simple_translation forms docstring? 53, 79 are code

    # Exclude contrib/forms/views.py docstring line 58? It's code (label=...)

    # Exclude admin/views/pages/usage.py docstring line 75? It's code (label)

    results.append({
        "file": rel,
        "line": lineno,
        "content": stripped
    })

# Deduplicate
seen = set()
unique = []
for r in results:
    key = (r["file"], r["line"])
    if key not in seen:
        seen.add(key)
        unique.append(r)

results = unique

# Group by file and subsystem
from collections import defaultdict
by_file = defaultdict(list)
by_subsystem = defaultdict(list)
for r in results:
    by_file[r["file"]].append(r["line"])
    parts = r["file"].split("/")
    if len(parts) >= 2:
        subsystem = parts[0] + "/" + parts[1]
    else:
        subsystem = parts[0]
    by_subsystem[subsystem].append(f"{r['file']}:{r['line']}")

flat = sorted([f"{r['file']}:{r['line']}" for r in results])

output = {
    "total": len(results),
    "flat": flat,
    "by_file": {k: sorted(v) for k, v in by_file.items()},
    "by_subsystem": {k: sorted(v) for k, v in by_subsystem.items()}
}

with open("/tmp/page_refs_clean.json", "w") as f:
    json.dump(output, f, indent=2, sort_keys=True)

print(json.dumps(output, indent=2, sort_keys=True))
